# ELT Pipeline Solution

## 1. Terraform Configuration (main.tf)

```hcl
terraform {
  required_providers {
    airbyte = {
      source  = "airbytehq/airbyte"
      version = "~> 0.6"
    }
  }
}

provider "airbyte" {
  server_url = "http://airbyte-abctl-control-plane:80/api/public/v1/"
}

# Snowflake Destination
resource "airbyte_destination_snowflake" "snowflake" {
  name         = "Snowflake Destination"
  workspace_id = var.workspace_id
  configuration = {
    database    = "address"
    schema      = "AIRBYTE_SCHEMA"
    warehouse   = "AIRBYTE_WAREHOUSE"
    role        = "AIRBYTE_ROLE"
    username    = "AIRBYTE_USER"
    credentials = {
      password = {
        password = "Snowflake@123"
      }
    }
    host = var.snowflake_host
  }
}

# Custom API Source
resource "airbyte_source_custom" "custom_api" {
  name         = "Custom API Source"
  workspace_id = var.workspace_id
  definition_id = var.custom_api_definition_id
  configuration = {}
}

# Flat Files Source (CSV)
resource "airbyte_source_file" "flat_files" {
  name         = "Flat Files Source"
  workspace_id = var.workspace_id
  definition_id = "778daa7c-feaf-4db6-96f3-70fd645acc77"
  configuration = {
    url      = "https://drive.google.com/uc?export=download&id=1xykJApWNgfi2pWv0f44j0y3dA7TrF-N9"
    format   = "csv"
    dataset_name = "state"
    provider = {
      storage = "HTTPS"
    }
  }
}

# MongoDB Source
resource "airbyte_source_mongodb_v2" "mongodb" {
  name         = "MongoDB Source"
  workspace_id = var.workspace_id
  definition_id = "b2e713cd-cc36-4c0a-b5bd-b47cb8a0561e"
