  definition_id = "decd338e-5647-4c0b-adf4-da0e75f5a750"
  configuration = {
    host     = "elt-postgres"
    port     = 5432
    database = "address"
    username = "postgres"
    password = "testelt"
    schemas  = ["public"]
    ssl_mode = {
      disable = {}
    }
  }
}

# S3 Source
resource "airbyte_source_s3" "s3" {
  name         = "S3 Source"
  workspace_id = var.workspace_id
  definition_id = "69589781-7828-43c5-9f63-8925b1c1ccc2"
  configuration = {
    bucket = "address-bucket"
    aws_access_key_id     = "test"
    aws_secret_access_key = "test"
    endpoint              = "http://elt-localstack:4566"
    region_name           = "us-west-2"
    streams = [
      {
        name   = "CBSA"
        format = {
          jsonl_format = {}
        }
        globs = ["CBSA.jsonl"]
      }
    ]
  }
}

# Connection: Custom API to Snowflake
resource "airbyte_connection" "custom_api_to_snowflake" {
  name           = "Custom API to Snowflake"
  source_id      = airbyte_source_custom.custom_api.source_id
  destination_id = airbyte_destination_snowflake.snowflake.destination_id
