## 2. SQL Transformations

### states.sql

```sql
-- Model: states
-- Description: Each record represents a state with aggregated metrics

WITH state_base AS (
    SELECT 
        abbreviation,
        name
    FROM state
),

-- Aggregate Asian population by state
asian_population AS (
    SELECT 
        state,
        COALESCE(SUM(asian_population), 0) AS num_asian
    FROM zip_data
    GROUP BY state
),

-- Count counties per state
county_counts AS (
    SELECT 
        state,
        COUNT(DISTINCT county) AS num_counties
    FROM country
    GROUP BY state
),

-- Find county with highest average income per household per state
county_income AS (
    SELECT 
        c.state,
        c.county,
        AVG(zd.avg_income_per_household) AS avg_income
    FROM country c
    LEFT JOIN zip_data zd ON c.zip_code = zd.zip_code
    GROUP BY c.state, c.county
),

county_ranked AS (
    SELECT 
        state,
        county,
        avg_income,
        ROW_NUMBER() OVER (
            PARTITION BY state 
            ORDER BY avg_income DESC, county ASC
        ) AS rn
    FROM county_income
    WHERE avg_income IS NOT NULL
),

highest_income_county AS (
    SELECT 
        state,
        county AS county_with_highest_average_income_per_household
    FROM county_ranked
    WHERE rn = 1
),

-- Calculate female population percentage per state
female_population_stats AS (
    SELECT 
        state,
        SUM(female_population) AS total_female,
        SUM(male_population) + SUM(female_population) AS total_population
    FROM zip_data
    GROUP BY state
),

female_percentage AS (
    SELECT 
        state,
        CASE 
            WHEN total_population > 0 THEN (total_female * 1.0 / total_population)
            ELSE 0 
        END AS female_pct
    FROM female_population_stats
),

avg_female_pct AS (
    SELECT AVG(female_pct) AS avg_pct
    FROM female_percentage
),

-- Count CBSA metro officers per state
cbsa_metro_counts AS (
    SELECT 
        zd.state,
        COUNT(DISTINCT CASE WHEN cb.CBSA_type = 'metro' THEN cb.CBSA END) AS metro_count
    FROM zip_data zd
    INNER JOIN CBSA cb ON zd.CBSA = cb.CBSA
    WHERE cb.CBSA_type = 'metro'
    GROUP BY zd.state
)

SELECT 
    sb.abbreviation,
    sb.name,
    hic.county_with_highest_average_income_per_household,
    COALESCE(ap.num_asian, 0) AS num_asian,
    COALESCE(cc.num_counties, 0) AS num_counties,
    CASE 
        WHEN fp.female_pct > (SELECT avg_pct FROM avg_female_pct) THEN 1 
        ELSE 0 
    END AS higher_avg_female_per,
    CASE 
        WHEN COALESCE(cmc.metro_count, 0) > 50 THEN 1 
        ELSE 0 
    END AS greater_than_50_CBSA_metro
FROM state_base sb
LEFT JOIN asian_population ap ON sb.abbreviation = ap.state
LEFT JOIN county_counts cc ON sb.abbreviation = cc.state
LEFT JOIN highest_income_county hic ON sb.abbreviation = hic.state
LEFT JOIN female_percentage fp ON sb.abbreviation = fp.state
LEFT JOIN cbsa_metro_counts cmc ON sb.abbreviation = cmc.state
```
